elName": "绝对控股2家公司", "labelTranslateName": "强大经济实力公司"}, {"labelCode": "new_strategic_industry", "labelDefinition": "该企业申请、授权的专利属于以重大技术突破和重大发展需求为基础，对经济社会全局和长远发展具有重大引领带动作用，知识技术密集、物质资源消耗少、成长潜力大、综合效益好的战略性新兴产业。", "labelName": "战略性新兴领域创新能力", "labelTranslateName": "新兴领域创新企业"}, {"labelCode": "has_patent_invention", "labelDefinition": "该企业拥有一项或多项发明专利。发明专利是指针对产品、方法或其改进所提出的新技术方案。", "labelName": "拥有发明专利"}, {"labelCode": "pat_grant_top", "labelDefinition": "据企业官方和专利局网站信息显示，该企业在计算推算领域获得的专利授权数量在同行业位于前列。", "labelName": "专利授权量同领域前20%"}, {"labelCode": "tech_layout_better", "labelDefinition": "该企业在技术方面拥有更加先进、更加优秀的技术水平和技术资源，优于同行业能够更好地满足市场需求并持续推出更具市场竞争力的产品或服务。", "labelName": "技术布局优于同行"}, {"labelCode": "esg_certificate_e", "labelDefinition": "该企业拥有环保绿色相关资质认证。", "labelName": "拥有绿色资质", "labelTranslateName": "拥有绿色资质"}, {"labelCode": "own_independent_brand", "labelDefinition": "该企业拥有中软华腾自主品牌。", "labelName": "拥有自主品牌"}, {"labelCode": "national_multistore", "labelDefinition": "企业在全国拥有多家连锁直营店铺。", "labelName": "全国多家直营店", "labelTranslateName": "全国门店布局"}], "showTypeUrl": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20250520/ptcard_128e85b893a640e8940c74c70daada54.png", "showTypeUrlDark": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20251208/a7401c7dc5b291eef900ff6b78327e18_f2a16bd811034ae78dea2e01b9945aee.png", "smallHrLogoUrl": "https://img01.51jobcdn.com/imehire/userportrait/7/6507/6506222/1741827811473_small.jpg?1741827815?v=20260317", "term": "0", "termStr": "全职", "triggerBatchDeliver": true, "updateDateTime": "2026-04-07 16:33:04", "userInteractionOnlineLabel": 3, "workAreaCode": "040300", "workYear": "5", "workYearString": "3年及以上"}
